const items = $input.all();

const realAds = items.map(item => {
  const json = item.json;
  const data = json.snapshot || json;

  // ฟังก์ชันช่วยแกะข้อความ (ไม่ว่าจะเป็น String หรือ Object)
  const safeString = (val) => {
    if (!val) return "";
    if (typeof val === 'string') return val;
    // ถ้าเป็น Object ให้แปลงเป็นข้อความ JSON จะได้ไม่ออกมาเป็น [object Object]
    return JSON.stringify(val);
  };

  // ดึงค่าและแปลงให้ปลอดภัยทันที
  let rawText = safeString(data.primaryText) ||
                safeString(data.body) ||
                safeString(data.title) ||
                safeString(data.caption) ||
                (data.cards && data.cards.length > 0 ? safeString(data.cards[0].body) : "") ||
                "ไม่มีข้อความ";

  return {
    text: rawText, // ตอนนี้เป็น Text ชัวร์ๆ แล้ว
    imageUrl: data.imageUrl || data.thumbnail || "",
    original_data: data
  };
}).filter(ad => {
  return ad.text !== "ไม่มีข้อความ" && 
         ad.text !== "" && 
         !ad.text.includes("{{product.name}}");
});

return {
  json: {
    ads_data: realAds,
    total_ads: realAds.length,
    has_active_ads: realAds.length > 0
  }
};

// ดึงข้อมูลจากโหนดก่อนหน้า (Google Sheets - Get Rows)
const allResults = $input.all().map(item => item.json);

// กรองเฉพาะข้อมูลของ "วันนี้" (เผื่อใน Sheet มีของเก่าปน)
// ถ้าใน Sheet คอลัมน์วันที่ชื่อ 'Date' ให้ใช้ item.Date
// ถ้าไม่มีคอลัมน์วันที่ หรืออยากเอาทั้งหมด ให้ลบบรรทัด filter ทิ้งได้ครับ
const todayStr = new Date().toLocaleDateString('en-CA'); // format YYYY-MM-DD
// const todaysData = allResults.filter(item => item.Date && item.Date.includes(todayStr)); 
const reportData = allResults; // ใช้ทั้งหมดไปก่อน (ถ้าอยากกรองค่อยแก้)

let html = `
<html>
<head>
<style>
  body { font-family: 'Sarabun', sans-serif; }
  table { border-collapse: collapse; width: 100%; border: 1px solid #ddd; }
  th, td { border: 1px solid #ddd; padding: 12px; text-align: left; vertical-align: top; }
  th { background-color: #007bff; color: white; }
  tr:nth-child(even) { background-color: #f2f2f2; }
</style>
</head>
<body>
  <h2>📊 รายงานสรุปคู่แข่ง (จาก Google Sheets)</h2>
  <p>จำนวนรายการทั้งหมด: <strong>${reportData.length}</strong> ราย</p>

  <table>
    <tr>
      <th style="width: 20%">คู่แข่ง</th>
      <th style="width: 10%">Ads</th>
      <th style="width: 35%">กลยุทธ์</th>
      <th style="width: 35%">ข้อเสนอ</th>
    </tr>
`;

reportData.forEach(item => {
  // ⚠️ เช็คชื่อหัวตารางใน Sheet ของคุณให้ตรงกับตัวแปรด้านล่างนี้
  // เช่นถ้าใน Sheet หัวตารางเป็น "Competitor" ก็ใช้ item.Competitor
  const name = item.Competitor || item.Competitor_Name || 'Unknown';
  const ads = item.Ads_Count || item.Ads_Found || 0;
  const strategy = item.Strategy || item.Strategy_Summary || '-';
  const offer = item.Key_Offer || item.Key_Offer || '-';

  html += `
    <tr>
      <td><strong>${name}</strong></td>
      <td style="text-align: center;">${ads}</td>
      <td>${strategy}</td>
      <td>${offer}</td>
    </tr>
  `;
});

html += `
  </table>
</body>
</html>
`;

return {
  json: {
    html_report: html,
    subject_date: new Date().toLocaleDateString('th-TH')
  }
};

